import{_ as a,o as i,c as t,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap/index.md","filePath":"roadmap/index.md","lastUpdated":null}'),l={name:"roadmap/index.md"};function r(s,e,o,d,c,m){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>DINOForge follows a milestone-based development plan, building from low-level runtime to high-level content packs.</p><h2 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h2><h3 id="m0-—-reverse-engineering-harness" tabindex="-1">M0 — Reverse-Engineering Harness ✅ <a class="header-anchor" href="#m0-—-reverse-engineering-harness" aria-label="Permalink to &quot;M0 — Reverse-Engineering Harness :white_check_mark:&quot;">​</a></h3><p><strong>Status</strong>: Complete</p><p>Install BepInEx, confirm plugin loading, test plugin, dump entities.</p><ul><li>BepInEx 5.4.23.5 installed with modified Doorstop pre-loader</li><li>Runtime builds to <code>BepInEx/ecs_plugins/DINOForge.Runtime.dll</code> (26KB)</li><li>Entity Dumper, System Enumerator, Debug Overlay scaffolded</li><li>6/6 tests passing (xUnit + FluentAssertions)</li></ul><hr><h3 id="m1-—-runtime-scaffold" tabindex="-1">M1 — Runtime Scaffold ✅ <a class="header-anchor" href="#m1-—-runtime-scaffold" aria-label="Permalink to &quot;M1 — Runtime Scaffold :white_check_mark:&quot;">​</a></h3><p><strong>Status</strong>: Complete</p><p>Bootstrap plugin, version detection, logging, ECS introspection, debug overlay.</p><ul><li>BepInEx plugin bootstrap with version-aware initialization</li><li>ECS system and component discovery</li><li>Runtime logging infrastructure</li><li>Debug overlay foundation</li></ul><hr><h3 id="m2-—-generic-mod-sdk" tabindex="-1">M2 — Generic Mod SDK 🚧 <a class="header-anchor" href="#m2-—-generic-mod-sdk" aria-label="Permalink to &quot;M2 — Generic Mod SDK :construction:&quot;">​</a></h3><p><strong>Status</strong>: In Progress</p><p>Pack manifest format, registry system, schema validation, override model, dependency resolver.</p><ul><li>Pack manifest model with YAML loader (YamlDotNet)</li><li>Registry system for extensible content types</li><li>Schema validation pipeline (JsonSchema.Net / NJsonSchema)</li><li>Content override model with priority layering</li><li>Dependency resolver with cycle detection</li></ul><hr><h3 id="m3-—-dev-tooling" tabindex="-1">M3 — Dev Tooling 🚧 <a class="header-anchor" href="#m3-—-dev-tooling" aria-label="Permalink to &quot;M3 — Dev Tooling :construction:&quot;">​</a></h3><p><strong>Status</strong>: In Progress</p><p>Pack compiler CLI, validator CLI, test harness, diff tools, diagnostics.</p><ul><li>PackCompiler CLI (validate, build, assets commands)</li><li>DumpTools CLI with Spectre.Console</li><li>Schema validation integration</li><li>Pack diffing and compatibility checks</li></ul><hr><h3 id="m3-5-—-qa-harness" tabindex="-1">M3.5 — QA Harness 📆 <a class="header-anchor" href="#m3-5-—-qa-harness" aria-label="Permalink to &quot;M3.5 — QA Harness :calendar:&quot;">​</a></h3><p><strong>Status</strong>: Planned</p><p>BepInEx QA plugin with IPC (named pipe/WebSocket), external test driver, ECS state assertions, CI-runnable integration tests.</p><ul><li>In-game QA plugin that accepts commands via IPC</li><li>External test driver for automated testing</li><li>ECS state assertion framework</li><li>CI integration for automated pack validation</li></ul><hr><h3 id="m4-—-warfare-domain-plugin" tabindex="-1">M4 — Warfare Domain Plugin 📆 <a class="header-anchor" href="#m4-—-warfare-domain-plugin" aria-label="Permalink to &quot;M4 — Warfare Domain Plugin :calendar:&quot;">​</a></h3><p><strong>Status</strong>: Planned</p><p>Factions, doctrines, unit classes, weapons, waves, defenses.</p><ul><li>Faction archetype system (Order, Industrial Swarm, Asymmetric)</li><li>5 factions: Republic, CIS, West, Classic West Enemy, Guerrilla</li><li>Unit role matrix with 13 shared slots</li><li>Weapon classes and defense tags</li><li>Wave composition templates</li><li>Doctrine modifiers</li></ul><hr><h3 id="m5-—-first-example-packs" tabindex="-1">M5 — First Example Packs 📆 <a class="header-anchor" href="#m5-—-first-example-packs" aria-label="Permalink to &quot;M5 — First Example Packs :calendar:&quot;">​</a></h3><p><strong>Status</strong>: Planned</p><p>West vs Classic Enemy, then Republic vs CIS, then Guerrilla.</p><ul><li>Modern Warfare theme pack (West vs Classic West Enemy)</li><li>Star Wars Clone Wars theme pack (Republic vs CIS)</li><li>Asymmetric warfare pack (West vs Guerrilla)</li><li>Level 1 content (zero-new-model build)</li></ul><hr><h3 id="m6-—-content-polish" tabindex="-1">M6 — Content Polish 📆 <a class="header-anchor" href="#m6-—-content-polish" aria-label="Permalink to &quot;M6 — Content Polish :calendar:&quot;">​</a></h3><p><strong>Status</strong>: Planned</p><p>Signature structures, better models, faction audio, campaign wrappers.</p><ul><li>Level 2 content (selective model swaps for key units)</li><li>Faction-specific audio packs</li><li>Campaign/scenario scripting</li><li>Polish and balance iteration</li></ul><hr><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><blockquote><p>A new mod can be created mostly by editing validated pack files and running the toolchain, without new reverse engineering.</p></blockquote><p>If every mod still needs runtime surgery, the framework failed.</p>',46)])])}const h=a(l,[["render",r]]);export{u as __pageData,h as default};
